namespace ClaudeCode.Core.Messages;

using System.Text.Json.Serialization;

/// <summary>
/// Token usage statistics returned by the Anthropic API for a single request.
/// All counts are non-negative; fields absent in the API response default to zero.
/// </summary>
public record UsageInfo
{
    /// <summary>Number of tokens in the prompt sent to the model.</summary>
    [JsonPropertyName("input_tokens")]
    public int InputTokens { get; init; }

    /// <summary>Number of tokens generated by the model.</summary>
    [JsonPropertyName("output_tokens")]
    public int OutputTokens { get; init; }

    /// <summary>Tokens served from the prompt cache (billed at the cache-read rate).</summary>
    [JsonPropertyName("cache_read_input_tokens")]
    public int CacheReadInputTokens { get; init; }

    /// <summary>Tokens written into the prompt cache (billed at the cache-write rate).</summary>
    [JsonPropertyName("cache_creation_input_tokens")]
    public int CacheCreationInputTokens { get; init; }

    /// <summary>Total tokens billed, combining input, cache-read, and output counts.</summary>
    [JsonIgnore]
    public int TotalTokens => InputTokens + CacheReadInputTokens + OutputTokens;
}
